(window.courseContent = window.courseContent || {})["000007"] = {"files/Акушерство и Гинекология/Теми/1-msg-Аборт.html":"<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Аборт</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.8em;\n      margin-bottom: 0.15em;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0.1em; }\n    h4 { font-size: 1.05em; margin-bottom: 0.1em; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.2em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    p + ul, p + ol { margin-top: -0.5em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0.1em; \n    }\n    ul, ol { \n      margin: 0.5em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.3em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.2em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image styles are handled by inline styles and data-width attributes */\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n      line-height: 1 !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.3em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.2em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.3em; }\n      h2 { font-size: 1.1em; }\n      h3 { font-size: 1em; }\n      p { margin: 0.5em 0; }\n      ul, ol { padding-left: 1.2em; }\n      li { margin: 0.1em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 4px 6px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      max-width: 500px;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        let lines = text.split('\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n          \n          let isUl = /^[-*]s+(.+)/.test(content);\n          let isOl = /^d+.s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]s+(.+)/) : content.match(/^d+.s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/**(.+?)**/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/*(.+?)*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/[(.+?)]((.+?))/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            tooltip.style.left = rect.left + 'px';\n            tooltip.style.top = (rect.bottom + 5) + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center; font-size: 1.65em;\"></h1><h3 style=\"font-size: 1.1em;\"></h3><h1 style=\"text-align: center; font-size: 1.65em;\"><span style=\"color: rgb(88, 129, 87); font-size: inherit; font-weight: 600;\"></span></h1><h1 style=\"text-align: center;\">АБОРТ И СПОНТАНЕН АБОРТ</h1><h2>Определение и епидемиологични данни</h2><p>Спонтанен аборт е бременност, която завършва преди плодът да е достигнал своята жизнеспособност. Днес границата на жизнеспособност се приема за 23-ата гестационна седмица или тегло на плода при раждане от 400 грама. Прекъсването на бременността след този срок се дефинира като преждевременно раждане (ако детето е живо) или като мъртво раждане (интраутеринна смърт на плода). Спонтанните аборти се класифицират хронологично на ранни (до 13-а гестационна седмица) и късни (между 14-а и 22-а гестационна седмица).</p><p>Честотата на тези състояния варира значително — от 10% до 70%. Проспективни изследвания показват, че около 15% от всички клинично диагностицирани бременности завършват с аборт. Когато се вземат предвид и биохимичните бременности, установени единствено чрез повишени нива на β-hCG, честотата на абортите достига 50-70%. Повечето от тези много ранни аборти протичат незабелязано под формата на малко по-обилно и закъсняло менструално кръвотечение. След втория триместър честотата спада рязко до нива от 1-2%.</p><hr><h2>Етиология и патогенеза</h2><p>Причините за настъпване на аборт са многобройни и се делят на директни и индиректни фактори.</p><h3>Генетични аномалии</h3><p>Генетичните дефекти на ембриона са най-честата причина за спонтанен аборт. При генетично изследване на тъкани от аборти се установяват хромозомни аномалии в до 60% от случаите, като най-чести са тризомиите, триплоидиите, тетраплоидиите и транслокациите. Други дефектни предразположения на ембриона без видими хромозомни аномалии също са значим фактор за загуба на бременността.</p><h3>Ендокринни причини</h3><p>Основен фактор е инсуфициенцията на corpus luteum, при която жълтото тяло е слабо развито и произвежда недостатъчно количество гестагени. Тази констелация в пери- и постимплантационната фаза често води до аборт, поради което при доказана недостатъчност се прилага поддържаща терапия с гестагени през първите 10-12 седмици. Други ендокринни причини включват заболявания на щитовидната жлеза и захарен диабет, където хипергликемията води до комплексни нарушения в нидацията и развитието.</p><h3>Инфекциозни фактори</h3><p>Инфекциите могат да бъдат асцендиращи (от вагината към цервикса и матката) или системни. Бактериите могат да причинят цервицит или ендометрит, които водят до аборт или предизвикват септично състояние. Вирусите на рубеола, морбили и цитомегалия, както и бактерии (листериоза, луес) или протозои (токсоплазмоза), са доказани причинители на аборти.</p><h3>Анатомични аномалии на матката</h3><p>Към тях спадат:</p><ul><li>Вродени малформации като uterus bicornis (двурога матка), uterus subseptus и unicollis.</li><li>Uterus myomatosus, особено при наличие на субмукозни миоми, които пречат на правилната нидация.</li><li>Синехии (сраствания) в cavum uteri, често възникващи след ятрогенно нараняване при кюретаж. При синдрома на Asherman матката е напълно срастнала и кухината ѝ е заличена тотално или субтотално.</li></ul><h3>Цервикална инсуфициенция</h3><p>Това състояние обикновено води до късни аборти през втория триместър. Характеризира се с прогресивно, асимптоматично скъсяване и дилатация на шийката, при което тя губи своята затваряща и защитна функция. Това позволява на асцендиращи инфекции да достигнат долния полюс на яйцето.</p><hr><h2></h2><p><span style=\"color: rgb(88, 129, 87); font-size: 1.3em; font-weight: 600;\">КЛИНИЧНО КЛАСИФИЦИРАНЕ И СИМПТОМАТИКА</span></p><p>Класифицирането на спонтанните аборти се основава на патофизиологичното протичане и съпътстващата клинична симптоматика. Главният симптом е вагиналното кървене, което може да варира от оскъдно петно до застрашаващо живота масивно кръвотечение, като често е по-изразено през втория триместър. Болките в долната част на корема са друг водещ признак — те обикновено са локализирани медиално, имат коликообразен характер и често се възприемат от пациентките като засилени менструални оплаквания.</p><ul><li><strong>Abortus imminens (Заплашващ аборт):</strong> Това състояние означава, че бременността е все още интактна, но са налице първите признаци на заплаха. Симптомите включват различно по сила вагинално кървене и леки, дърпащи болки, съответстващи на реактивни контракции на миометриума. Прогнозата обикновено е добра и често не се стига до прекъсване на бременността, макар рискът от аборт да остава 2-3 пъти по-висок в сравнение с асимптоматичните случаи.</li><li><strong>Missed abortion (Задържан аборт):</strong> Характеризира се с ранно умиране на плода в различни стадии на развитие (обикновено през първия триместър), без той да бъде изхвърлен веднага. Първоначално симптомите са минимални или липсват, като същинските контракции и кървене се появяват по-късно. Диагнозата често се поставя случайно при ултразвуково изследване, което показва по-малка матка от очакваното и липса на виталност.</li><li><strong>Негодно за развитие яйце (Blighted ovum):</strong> При тази форма ембриобластът изобщо не се развива поради дефектно предразположение. В резултат на това възниква само хорионална кухина без наличие на ембрион или жълтъчно мехурче. Клиничната му изява е сходна с тази на задържания аборт.</li><li><strong>Abortus incipiens (Започващ аборт):</strong> Абортът е вече в ход, като е налице активно вагинално кървене и спазматични болки в долната част на корема.</li><li><strong>Abortus incompletus (Незавършен аборт):</strong> При него части от трофобластната или ембрионалната тъкан са вече изхвърлени, но в матката все още остава материал. Пациентките често описват изхвърляне на „тъканни парчета“, придружено от силни коликообразни болки.</li><li><strong>Abortus completus (Завършен аборт):</strong> Плодът е напълно изхвърлен, кървенето значително намалява или спира, а матката е контрахирана и малка.</li></ul><hr><h2>ДИАГНОСТИКА И ДИФЕРЕНЦИАЛНА ДИАГНОЗА</h2><p>Диагностиката изисква комплексен подход, включващ гинекологичен преглед, ултразвук и лабораторни тестове. Вагиналният преглед при заплашващ аборт обикновено установява затворен цервикален канал, докато при започващ или незавършен аборт шийката е леко отворена. Златният стандарт в диагностиката е <b>трансвагиналната сонография</b>. Тя позволява да се установи интраутеринното положение и сърдечната активност на плода. Ако при ембрионална дължина от 3-4 mm или повече не се установи сърдечна дейност, това е сигурно доказателство за липсваща виталност. При негодно за развитие яйце диагнозата се базира на <b>изобразяването на хорионална кухина</b>, по-голяма от 20 mm, която не съдържа ембрионални структури. Стойността на <b>β-hCG</b> в серума също е важен маркер — стагниращите или спадащите нива са показателни за неуспешна бременност.</p><p>Диференциалната диагноза е наложителна, тъй като симптомите на аборт не са специфични. Трябва да се изключат следните състояния:</p><ul><li><strong>Тубарна (екстраутеринна) бременност:</strong> Изключва се чрез сонография и проследяване на β-hCG нивата.</li><li><strong>Кървене от цервикса:</strong> Може да се дължи на голяма ектопия или инвазивен карцином, което се установява чрез колпоскопия и цитонамазка.</li><li><strong>Интраабдоминална патология:</strong> Овариални кисти (руптура или торзио), остър апендицит или гастроентерит, които се диагностицират чрез сонография и изследване на възпалителни параметри.</li></ul><hr><h2>СЕПТИЧЕН АБОРТ</h2><p>Септичният аборт е потенциално животозастрашаващо усложнение, представляващо асцендираща инфекция с риск от сепсис. Инфекцията може да се разпространи бързо към параметралните тъкани, тръбите и аднексите, водейки до пелвиоперитонит и септичен шок. Симптомите включват гнойно и лошо миришещо течение, висока температура, втрисане, тахикардия и силна болезненост на матката при натиск. Възможно е развитие на тежки усложнения като бъбречна недостатъчност, ARDS и дисеминирано интраваскуларно кръвосъсирване. Септичният аборт често е следствие от нелегално прекъсване на бременността с нестерилни инструменти. Терапията изисква незабавна интравенозна широкоспектърна антибиотична поддръжка и инструментално отстраняване на инфектирания материал от матката.</p><hr><h2>ХАБИТУАЛЕН АБОРТ</h2><p>За хабитуални аборти се говори при наличие на три или повече последователни спонтанни аборта, като честотата им е около 0,5-1%. Причините са многообразни:</p><ul><li><strong>Генетични:</strong> В до 12% от двойките се установяват хромозомни аберации (най-често балансирани транслокации).</li><li><strong>Ендокринологични:</strong> PCO синдром, хронична недостатъчност на corpus luteum (недостатъчен прогестерон), заболявания на щитовидната жлеза или захарен диабет.</li><li><strong>Анатомични:</strong> Малформации на матката (uterus subseptus), миоми или вътрематочни сраствания.</li><li><strong>Имунологични:</strong> Смущения в имунологичната бариера между майката и плода или синдром на антифосфолипидните антитела (тромбофилия), който типично води до аборти във втория триместър.</li></ul><p>Диагностиката изисква кариограма на двойката, точно изследване на цикъла, подробен ултразвук, хистероскопия и изследване на цервикален секрет за инфекции.</p><hr><h2>ПРЕКЪСВАНЕ НА БРЕМЕННОСТТА И ТЕРАПИЯ</h2><p>Терапевтичното поведение зависи от стадия на аборта и гестационната възраст.</p><ul><li><strong>Терапия при заплашващ аборт:</strong> Включва физическо щадене, покой на легло и терапия с магнезий за релаксация на миометриума. При доказана инсуфициенция на жълтото тяло е целесъобразна поддържаща терапия с гестагени до 12-а седмица.</li><li><strong>Оперативно прекъсване:</strong> До 14-а гестационна седмица (или бипариетален диаметър до 30 mm) се предпочита вакуум-аспирация (смукателен кюретаж), който е по-малко рисков от металния кюретаж. Преди манипулацията шийката се подготвя с простагландини.</li><li><strong>Медикаментозно прекъсване:</strong> До 49-ия ден е възможно използването на антигестагена Mifepriston, последван от простагландин (Misoprostol), който предизвиква контракции и изхвърляне на плода. След 14-а седмица се прилага медикаментозна индукция с утеротоници, последвана от инструментална ревизия на матката.</li><li><strong>Усложнения:</strong> Най-сериозната опасност при кюретаж е перфорацията на матката поради меките ѝ стени по време на бременност. Късни усложнения могат да бъдат цервикална инсуфициенция и интраутеринни сраствания.</li><li><strong>Резус-профилактика:</strong> При жени с Rh-отрицателна кръвна група задължително се прилага анти-D-имуноглобулин за предотвратяване на изоимунизация.</li></ul>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false}\n  ]\n});\n</script>\n</body>\n</html>","files/Акушерство и Гинекология/Теми/3-msg-Нормален и патологичен пуерпериум.html":"<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Нормален и патологичен пуерпериум</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center\">Нормален следродов период (Пуерпериум)</h1><p><strong>Следродовият период</strong>, известен още като <strong>пуерпериум</strong>, обхваща времето от момента на изхвърлянето на плацентата до <strong>6–8 седмици</strong> след раждането. Това е период на интензивно физиологично възстановяване, през който организмът на жената се стреми да се върне към състоянието си отпреди бременността. Процесите включват заздравяване на родилните наранявания, обратно развитие на гениталната и други системи, начало на лактацията и възстановяване на яйчниковата функция.</p><hr><h2>Физиологични процеси на обратно развитие</h2><p>През пуерпериума протича инволюция на органите, които са претърпели най-големи промени по време на бременността.</p><h3>Инволюция на матката</h3><p>Матката претърпява най-драстичните промени в своето тегло и размери:</p><ul><li><strong>Тегло:</strong> В края на бременността матката тежи около <strong>1000 g</strong>, а в края на следродовия период се редуцира до <strong>50–80 g</strong>.</li><li><strong>Стимулиращи фактори:</strong> Процесът се подпомага от маточни контракции. Кърменето е естествен стимулатор, тъй като засукването предизвиква освобождаване на <strong>окситоцин</strong> от задния дял на хипофизата.</li><li><strong>Ранева повърхност:</strong> Вътрешната повърхност на матката (особено мястото на закрепване на плацентата) представлява открита рана. Чрез контракции, тромбозиране на съдовете и миграция на <strong>гранулоцити</strong> и <strong>лимфоцити</strong>, тя се преобразува и епителизира напълно до края на периода.</li></ul><h3>Лохии (Lochia)</h3><p>Лохиите (течението в следродовия период) са раневият секрет, който се образува във възникналото от отлепването па плацентата рапево легло. Количеството. цветът и качеството им се променят в хода па следродовия период и зависят от състава па лохиите (кръв, лимфна течност, серозен ексудат, клетъчен детрит, макрофаги). Средното количество на лохиалния секрет варира от 200 до 500 g. Тъй като във влагалището винаги има микроорганизми, лохиите по принцип трябва да се считат за инфекциозни. </p><table><thead><tr><th><span style=\"color: rgb(88, 129, 87)\">Време</span></th><th><span style=\"color: rgb(88, 129, 87)\">Стоеж на фундуса</span></th><th><span style=\"color: rgb(88, 129, 87)\">Цервикс</span></th><th><span style=\"color: rgb(88, 129, 87)\">Лохии</span></th></tr></thead><tbody><tr><td><strong>Post partum</strong></td><td>между пъпа и симфизата </td><td>широк </td><td><strong>Lochia rubra (кръвенисти) </strong></td></tr><tr><td><strong>След 24 часа </strong></td><td>на височина на пъпа </td><td>начало на формиране </td><td> </td></tr><tr><td><strong>1-ви ден </strong></td><td>всеки ден 1 напречен пръст по -ниско </td><td> </td><td> </td></tr><tr><td><strong>3-ти ден </strong></td><td>N/3 </td><td>формиран </td><td> </td></tr><tr><td><strong>4-ти ден </strong></td><td>N/4 </td><td> </td><td><strong>Lochia fusca (кафяво-червени)</strong></td></tr><tr><td><strong>5-ти ден </strong></td><td>между пъпа и симфизата </td><td>проходим за пръста </td><td> </td></tr><tr><td><strong>2 седмици </strong></td><td> </td><td> </td><td><strong>Lochia flava  (жълтеникави)</strong></td></tr><tr><td><strong>3 седмици </strong></td><td> </td><td> </td><td><strong>Lochia alba (белезникави) </strong></td></tr></tbody></table><hr><h2>Хормонални промени след раждането</h2><p>Основните хормонални изменения са следствие от рязкото отпадане на плацентарната продукция и постепенното активиране на <strong>хипоталамо-хипофизо-овариалната ос</strong>.</p><h3>Динамика на плацентарните и хипофизарните хормони</h3><ul><li><strong>Човешки хорионгонадотропин (hCG):</strong> Нивата му спадат силно още в първия ден след родоразрешението.</li><li><strong>Естрогени и прогестерон:</strong> Редуцират се значително в първите дни след раждането.</li><li><strong>Пролактин:</strong> Майчината серумна концентрация спада бавно и непрекъснато, но при кърмене се стимулира повторно, което е от критично значение за поддържане на <strong>лактацията</strong>.</li><li>Рзавива се&nbsp;<p>релативен <strong>хипогонадотропизъм</strong> и <strong>хиперпролактинемия</strong>.</p></li></ul><h3>Възстановяване на овариалната функция</h3><p>По време на бременността гонадотропната функция на <strong>предния дял на хипофизата (ПДХ)</strong> е потисната от хормоните на <strong>corpus luteum graviditatis</strong> и плацентата. След раждането тя бавно поема своята функция.</p><h4>Зависимост от лактацията:</h4><ul><li><strong>При некърмещи жени:</strong> Първата овулация обикновено настъпва около <strong>6 седмици</strong> след раждането.</li><li><strong>При пълноценно кърмене:</strong> Около 80% от родилките изпадат в <strong>аменорея на кърменето</strong>. Това се дължи на потискане на ПДХ от състоянието на <strong>хиперпролактинемия</strong>.</li><li><strong>Ановулаторно кървене:</strong> Малка част от родилките могат да имат слабо редовно кървене, което не е истинска менструация, а ановулаторен цикъл.</li></ul><blockquote><strong>ЗАПОМНИ!&nbsp;</strong>Аменореята при кърмене не представлява сигурна защита от забременяване!</blockquote><hr><h2>Екстрагенитални процеси на обратно развитие</h2><p>Екстрагениталните промени обхващат нормализирането на водния баланс, сърдечно-съдовата система и кожата.</p><h3>Отделителна система и воден баланс</h3><ul><li><strong>Изхвърляне на течности:</strong> Настъпва значително изхвърляне на течности (5–10 литра), което води до намаление на минутния сърдечен обем.</li><li><strong>Форсирана диуреза:</strong> През първите дни се изхвърля складираната в екстравазалното пространство вода.</li><li><strong>Пикочен мехур:</strong> Характеризира се с намален тонус и по-висок капацитет. Поради възможен оток на уретрата от раждането, може да има нарушения в изпразването.</li><li><strong>Клинично изискване:</strong> Родилката трябва да може да уринира спонтанно в рамките на първите <strong>6 часа</strong> след раждането.</li></ul><h3>Сърдечно-съдова система и кожа</h3><ul><li>Сърдечно-съдовата система и дишането се нормализират бързо в дните след раждането.</li><li>Специфичните кожни изменения като <strong>стрии</strong> по корема и пигментации по лицето (<strong>chloasma uterinum</strong>) изчезват.</li></ul><hr><h2>Терапевтични насоки</h2><p>Най-добрите предпазни мерки за нормално обратно развитие включват кърмене, ранна мобилизация и осигуряване на спокойствие.</p><h4>Комплементарна терапия при забавяне на развитието:</h4><ul><li><strong>Фитотерапия:</strong> Употреба на чай от <strong>бял равнец</strong>, <strong>розов храст</strong>, <strong>овчарска торбичка</strong> и <strong>маточина</strong>.</li><li><strong>Положение по корем:</strong> Минимум 2 пъти дневно за 30 минути. Това осигурява физиологично положение на <strong>матката</strong> и по-добро изтичане на <strong>лохиите</strong>.</li></ul><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Патология на следродовия период</h1><p>В съвременната акушерска практика ранното разпознаване на отклоненията в пуерпериума е от критично значение, тъй като голяма част от усложненията, водещи до майчина смъртност, настъпват именно в периода <strong>post partum</strong>.</p><h3>Водещи симптоми на патологично протичане</h3><p>При съмнение за патологичен процес се наблюдават три основни признака:</p><ol><li><strong>Лошо обратно развитие</strong> (субинволуция) на матката, придружено от болезненост при палпация.</li><li><strong>Вагинални кръвотечения</strong>, които не съответстват на етапа на пуерпериума.</li><li><strong>Повишена телесна температура</strong>.</li></ol><hr><h2>Subinvolutio uteri (Субинволуция на матката)</h2><p><strong>Субинволуцията</strong> представлява забавено или недостатъчно обратно развитие на матката до нейните размери и състояние отпреди бременността.</p><h4>Етиология</h4><p>Най-често състоянието е следствие от преразтягане или отслабване на <strong>миометриума</strong>. Рискови фактори са:</p><ul><li>Протрахирано раждане.</li><li>Многоплодна бременност.</li><li><strong>Полихидрамнион</strong>.</li></ul><h4>Симптоми и диагностика</h4><ul><li><strong>Фундусът на матката</strong> се намира по-високо, отколкото се очаква за съответния следродов ден.</li><li>Матката се усеща \"хлабава\" или мека при палпация.</li><li>Течението (лохиите) е засилено и с подчертано кръвенист характер.</li></ul><h4>Терапия</h4><p>Основното лечение включва прилагането на <strong>утеротоници</strong> като <strong>окситоцин</strong> и <strong>метилергометрин</strong>. Най-добрата естествена профилактика остава редовното кърмене.</p><hr><h2>Задръжка на лохии (Lochiometra)</h2><p><strong>Лохиометра</strong> е усложнение, при което се преустановява нормалното оттичане на следродовия секрет от маточната кухина. Обикновено се развива между <strong>4-ия и 7-ия ден</strong> след раждането.</p><h4>Етиология</h4><p>Задръжката се получава поради механично запушване или спазъм на цервикалния канал от:</p><ul><li>Кръвни съсиреци.</li><li>Остатъци от околоплодните обвивки.</li><li>Спазъм на маточната шийка.</li></ul><h4>Симптоми</h4><ul><li><strong>Лохии:</strong> Силно редуцирани, напълно липсващи или със зловонна миризма.</li><li><strong>Матка:</strong> Мека, болезнена при натиск и с липсваща инволюция.</li><li><strong>Общо състояние:</strong> Родилката повишава температура и често съобщава за специфично <strong>челно главоболие</strong>.</li></ul><h4>Терапия</h4><p>Лечението е идентично с това при субинволуция (утеротоници). Дилатацията на цервикалния канал (чрез дилататори на Хегар или мануално) се прилага рядко поради висок риск от внасяне на инфекция.</p><hr><h2>Кръвоизливи в следродовия период</h2><p>Следродовите кръвоизливи са сред най-сериозните усложнения в акушерството. Те настъпват обикновено през <strong>първите две седмици</strong> след раждането и са водеща причина за майчина смъртност (18–22% от случаите, заедно с тромбоемболиите).</p><h3>А. Обща етиология и диагностика</h3><p>Кръвотеченията се класифицират според времето на настъпване и водещата причина. При всяко вагинално кървене е критично да се извърши бърза и точна диагностика.</p><h4>Основни причини за кървене</h4><ul><li><strong>Наранявания при раждането:</strong> Пропуснати разкъсвания на <strong>влагалището</strong>, <strong>перинеума</strong> или <strong>маточната шийка</strong>.</li><li><strong>Ретенция на тъкани:</strong> Остатъци от плацента, обвивки или добавъчна плацента (<strong>placenta succenturiata</strong>), дори ако основната плацента е изглеждала цяла.</li><li><strong>Късна атония:</strong> Загуба на тонус на <strong>миометриума</strong> в началото на пуерпериума.</li><li><strong>Плацентарни полипи:</strong> Късно усложнение от задържани частици.</li><li><strong>Ендометрит / Ендомиометрит:</strong> Възпаление на маточната лигавица и мускулатура.</li><li><strong>Нарушения в кръвосъсирването:</strong> Коагулопатии (вродени или придобити).</li></ul><h4>Диагностични стъпки</h4><ol><li><strong>Стерилен оглед с огледала:</strong> За изключване на травми по мекия родилен канал.</li><li><strong>Палпация:</strong> Оценка на височината на фундуса и консистенцията на матката.</li><li><strong>Ехография:</strong> Задължително изследване за проверка дали <strong>cavum uteri</strong> e празна.</li><li><strong>Лабораторни изследвания:</strong> Проследяване на протромбиново време, тромбоцити, фибриноген и антитромбин III.</li></ol><h3>Б. Късна маточна атония</h3><p>Атоничното кръвотечение може да възникне веднага след раждането или по-късно в отделението. То е опасно, защото в маточната кухина може да се събере голямо количество кръв, без това да е веднага видимо външно.</p><h4>Рискови фактори</h4><ul><li><strong>Протрахирано раждане:</strong> Продължителен процес, водещ до вторична родова слабост.</li><li><strong>Преразтягане на миометриума:</strong> При многоплодна бременност или <strong>полихидрамнион</strong>.</li><li><strong>Миоматозна матка:</strong> Наличието на миомни възли пречи на ефективната контракция.</li></ul><h3>Спешни мерки и мануални прийоми</h3><p>При установяване на атония първата мярка е механична стимулация за изпразване на матката от събраните коагулуми:</p><ul><li><strong>Прийом на Crede:</strong> Външна компресия на матката през коремната стена.</li><li><strong>Прийом на Hamilton:</strong> Бимануална компресия (едната ръка е във влагалището, другата – върху коремната стена).</li></ul><h3>В. Терапевтичен алгоритъм</h3><p>Лечението трябва да бъде незабавно и ефективно, преди да настъпят необратими нарушения в коагулацията.</p><h4>Консервативно и медикаментозно лечение</h4><ol><li><strong>Утеротоници:</strong> Интравенозна апликация на <strong>Окситоцин</strong>, <strong>Метилергометрин</strong> или простагландини (<strong>PGF2α</strong>).</li><li><strong>Мизопростол:</strong> При неуспех на първа линия се прилагат <strong>1000 µg мизопростол</strong> ректално.</li><li><strong>Обемно заместване:</strong> Своевременно преливане на плазмозаместители, еритроцитни концентрати и прясно замразена плазма.</li><li><strong>Маточна тампонада:</strong> Използване на марли, напоени с простагландини.</li></ol><h4>Хирургично лечение</h4><ul><li><strong>Кюретаж:</strong> Извършва се при съмнение за остатъци от плацента. Трябва да става под антибиотична защита и ехографски контрол поради риск от перфорация на меката маточна стена.</li><li><strong>Шев по B-Lynch:</strong> Специален компресионен шев върху матката за овладяване на кръвоизлива.</li><li><strong>Хистеректомия:</strong> Отстраняване на матката като последна възможност за спасяване живота на майката.</li></ul><blockquote><strong>ЗАПОМНИ!&nbsp;</strong>Терапията на силно следродово кръвотечение трябва да започне веднага. Всяко забавяне води до риск от терминална недостатъчност на кръвообращението.</blockquote><hr><h2>Температура</h2><p>Повишената температура в пуерпериума (<strong>пуерперална температура</strong>) се дефинира като стойности над <strong>38°C</strong>, произтичащи от инфекция на гениталния тракт. Тя засяга между <strong>5% и 10%</strong> от родилките и изисква прецизна диференциална диагноза.</p><h2>А. Диференциална диагноза на температурата</h2><p>Важно е да се направи разграничение между генитални инфекции и състояния с екстрагенитален произход.</p><h3>Екстрагенитални причини за температура</h3><p>Често температурата не е свързана директно с матката, а с други системи:</p><ul><li><strong>Гърди:</strong> „Прострелване“ (наход на мляко), <strong>пуерперален мастит</strong>.</li><li><strong>Хирургични рани:</strong> Инфектиран шев след секцио или епизиотомия.</li><li><strong>Съдова система:</strong> <strong>Тромбофлебит</strong>, дълбока венозна тромбоза или венозна тромбоза на синусите.</li><li><strong>Пикочни пътища:</strong> Цистит или <strong>пиелонефрит</strong>.</li><li><strong>Хематоми:</strong> Инфектирани кръвоизливи в параметрията или параколпиума.</li></ul><h2>Б. Пуерперален ендо(мио)метрит</h2><p>Това е най-честата инфекция на гениталиите, засягаща лигавицата (<strong>ендометрит</strong>) и мускулатурата (<strong>миометрит</strong>) на матката.</p><h4>Етиология и патогенеза</h4><p>Основните рискови фактори включват:</p><ul><li>Забавено обратно развитие (<strong>субинволуция</strong>) на матката.</li><li>Протрахирано раждане.</li><li>Дълъг период между спукването на околоплодния мехур и раждането.</li><li>Спектър от причинители: Стафилококи, стрептококи, <strong>E. coli</strong> и анаеробни грам-негативни микроорганизми.</li></ul><h4>Симптоми и диагностика</h4><p>Симптоматиката обикновено започва след <strong>2-ия ден post partum</strong>:</p><ul><li><strong>Температура:</strong> Субфебрилна до фебрилна с типично вълнообразно протичане.</li><li><strong>Лохии:</strong> Типично лошо миришещи и гнойни.</li><li><strong>Матка:</strong> Палпаторно е високостояща, отпусната и силно болезнена при натиск (особено по кантовете).</li><li><strong>Ехография:</strong> Показва отпусната матка с неясни граници на <strong>cavum uteri</strong>.</li></ul><h4>Терапия</h4><p>Лечението е комбинирано:</p><ol><li><strong>Контрактилни средства:</strong> Инфузия на <strong>Окситоцин</strong> а подпомагане на изпразването на матката.</li><li><strong>Антибиотици:</strong> Комбинация от Пеницилин или Цефалоспорин с <strong>Метронидазол</strong> (за покриване на анаеробната флора).</li></ol><h2>В. Пуерперален сепсис</h2><p>Това е тежко, животозастрашаващо състояние, при което инфекцията се разпространява от родилната рана в целия организъм.</p><h4>Патогенеза</h4><p>Разпространението на причинителите става по <strong>хематогенен</strong> или <strong>лимфогенен</strong> път от първичното огнище (ендомиометрит или тромбофлебит).</p><h4>Симптоми</h4><p>Към признаците на ендомиометрита се добавят:</p><ul><li>Висока температура, втрисане, <strong>тахикардия</strong> и хипотония.</li><li><strong>Лабораторни промени:</strong> Изразена левкоцитоза с олевяване, анемия, тромбоцитопения.</li><li><strong>Органни засягания:</strong> Жълтеница, ставни и мускулни болки.</li><li><strong>Шокова симптоматика:</strong> Цианоза, мултиорганна недостатъчност, бъбречна недостатъчност и <strong>DIC-синдром</strong> (преразходна коагулопатия).</li></ul><blockquote><strong>ЗАПОМНИ! </strong>Прокалцитонинът е основният параклиничен маркер за диагностика на сепсис.</blockquote><h4>Терапия</h4><p>Изисква незабавни интензивни медицински грижи:</p><ul><li><strong>Високодозирана антибиотична терапия:</strong> Първоначално широкоспектърна, по-късно ориентирана по антибиограмата.</li><li><strong>Стабилизиране:</strong> Централен венозен катетър, обемно заместване, корекция на коагулацията.</li><li><strong>Хепаринизация:</strong> Ниски дози за профилактика на тромбози.</li><li><strong>Хистеректомия:</strong> Като крайна мярка за отстраняване на септичното огнище при липса на ефект от консервативното лечение.</li></ul><blockquote><strong>ЗАПОМНИ! </strong>Макар и рядък днес, пуерпералният сепсис може да се развие фулминантно и трябва да се приема много сериозно!</blockquote><hr><h2>Тромбози и тромбоемболични заболявания в следродовия период</h2><p>Тромбоемболичните усложнения представляват значителен дял от майчината смъртност след раждане. В следродовия период балансът на кръвосъсирването е физиологично изместен към <strong>хиперкоагулация</strong>, което създава релативна тромбозна диспозиция.</p><h4>Рискови фактори</h4><ul><li><strong>Имобилизация:</strong> Намалено движение, особено след <strong>цезарово сечение</strong>.</li><li><strong>Оперативни интервенции:</strong> Вторично секцио, протрахирано раждане.</li><li><strong>Вродени тромбофилии:</strong> Мутация на <strong>фактор V (Leiden)</strong> или мутация на <strong>фактор II (протромбин)</strong>.</li><li><strong>Съдови промени:</strong> Разширение на вените и забавен кръвен ток през бременността.</li></ul><h3>А. Тромбофлебит</h3><p><strong>Тромбофлебитът</strong> е възпаление на повърхностните вени, което протича сравнително леко и без общи системни явления.</p><ul><li><strong>Етиология:</strong> Може да възникне спонтанно или след венозна пункция (напр. от периферен катетър/флексюла).</li><li><strong>Симптоми:</strong> Повърхностна, зачервена и болезнена индурация (втвърдяване). Няма разлика в обиколката на крайниците, липсват температура и тахикардия.</li><li><strong>Терапия:</strong> Симптоматично лечение с охлаждане, хепаринови мехлеми и алкохолни компреси. Важно е пациентките да <strong>не се имобилизират</strong>.</li></ul><h3>Б. Дълбоки венозни тромбози (ДВТ)</h3><p>Дълбоките тромбози на долните крайници и таза са сериозно състояние, развиващо се на базата на <strong>триадата на Вирхоф</strong>: лезия на съдовата стена, редуцирана скорост на кръвния ток и състав на кръвта.</p><h4>Клинична картина и симптоми</h4><p>Водещият симптом е <strong>оточен, зачервен и болезнен крак</strong>.</p><ul><li>Едностранно чувство на напрежение и тежест.</li><li><strong>Признак на Homann-Payr:</strong> Болка в прасеца при дорзална флексия на стъпалото.</li><li><strong>Признак на Lowenberg:</strong> Болка при натиск върху прасците.</li><li><strong>Признак на Mahler:</strong> Стъпаловидно покачващ се пулс (<strong>пълзящ пулс</strong>) при липса на съответно висока температура.</li></ul><h3>Диагностика и терапия</h3><ul><li><strong>Диагностика:</strong> Основен метод е <strong>Доплер-ехография</strong> (цветен Доплер). При установяване на ДВТ в пуерпериума е задължително изследване за тромбофилия.</li><li><strong>Терапия:</strong>&nbsp;</li><ul><li>Покой на легло (в острата фаза).</li><li>Пълно хепаринизиране с <strong>нискомолекулярен хепарин (LMWH)</strong>.</li><li>Забрана за <strong>i.m.</strong>&nbsp;инжекции поради риск от хематоми.</li><li>Последваща орална антикоагулация.</li></ul></ul><h3>В. Тромбоза на овариалните вени</h3><p>Рядко усложнение, което обикновено се проявява в първите седмици след раждането.</p><ul><li><strong>Симптоми:</strong> Болка в долната дясна част на корема и температура.</li><li><strong>Диагностика:</strong> Цветна ехография или <strong>МРТ</strong>.</li><li><strong>Терапия:</strong> Нискодозирано хепаринизиране.</li></ul><h3>Г. Белодробна емболия (БЕ)</h3><p><strong>Белодробната емболия</strong> е най-тежкото усложнение на ДВТ, при което тромб се откъсва и попада в белодробното кръвно русло.</p><h4>Симптоми и диагностика</h4><ul><li><strong>Клинична картина:</strong> Внезапна гръдна болка, диспнея, тахипнея, кашлица, изпотяване и шокова симптоматика.</li><li><strong>Диагностика:</strong>&nbsp;</li><ul><li><strong>Ехокардиография:</strong> Търсят се белези за дясно сърдечно обременяване.</li><li><strong>ЕКГ</strong> и Кръвно-газов анализ.</li><li><strong>Спирална компютърна томография (КТ-ангиография):</strong> Златен стандарт за верификация.</li></ul></ul><h3>Терапевтични мероприятия</h3><p>Изисква незабавно интензивно лечение:</p><ol><li><strong>Общи мерки:</strong> Подаване на кислород, високо положение на тялото, венозни течности.</li><li><strong>Специфична терапия:</strong> Терапевтично хепаринизиране (под контрол на <strong>РТТ</strong>).</li><li><strong>Лизираща терапия:</strong> Използване на стрептокиназа, урокиназа или <strong>tPA</strong> при тежки случаи.</li><li><strong>Хирургично лечение:</strong> Емболектомия или поставяне на кава-филтър.</li></ol><hr><h2>Ендокринологични нарушения в следродовия период</h2><p>След раждането могат да настъпят специфични нарушения в ендокринната система, най-често свързани с функцията на хипофизата. Тези състояния засягат лактацията, менструалния цикъл и общия метаболизъм на жената.</p><h3>А. Синдром на Шихан (Sheehan's Syndrome)</h3><p><strong>Синдромът на Шихан</strong> представлява следродова исхемична некроза на <strong>предния дял на хипофизата</strong>. Това е рядко, но сериозно усложнение на тежки родоразрешения.</p><h4>Етиология и патогенеза</h4><p>Състоянието е последица от тежка кръвозагуба по време или след раждането, водеща до <strong>хиповолемичен шок</strong>. Поради специфичното кръвоснабдяване на хипофизата през бременността, тя е изключително чувствителна към спад в кръвното налягане. Исхемията води до некроза на жлезистата тъкан.</p><h4>Симптоми</h4><p>Клиничните признаци се появяват едва когато са засегнати повече от <strong>75%</strong> от тъканта на аденохипофизата.</p><ul><li><strong>Първичен симптом:</strong> Липса или внезапно спиране на лактацията (<strong>агалактия</strong>).</li><li><strong>Късни симптоми:</strong></li><ul><li>Вторична аменорея и загуба на либидо.</li><li>Отпадане на вторичното окосмяване (пубисно и аксиларно).</li><li>Признаци на хипотиреоидизъм и надбъбречна недостатъчност.</li><li>Депигментация на кожата и чести хипогликемии.</li></ul></ul><blockquote><strong>ЗАПОМНИ!&nbsp;</strong>Типичният първи симптом на синдрома на Шихан е невъзможността за започване или внезапното спиране на лактацията.</blockquote><h4>Диагностика и терапия</h4><ul><li><strong>Диагностика:</strong> Изследване на нивата на гонадотропини, естрогени и провеждане на специализирани ендокринологични функционални тестове.</li><li><strong>Терапия:</strong> Доживотно заместително лечение с липсващите хормони — <strong>L-тироксин</strong>, кортикостероиди (<strong>кортизон</strong>) и полови хормони.</li></ul><h3>Б. Синдром на Киари-Фромел (Chiari-Frommel Syndrome)</h3><p>Това състояние представлява персистираща следродова аменорея и галакторея, която не е свързана с туморен процес.</p><h4>Етиология</h4><p>Дължи се на дисфункция в регулацията на пролактин-продуциращите клетки. Дори след края на периода на кърмене, нивата на пролактин остават високи, което блокира нормалния месечен цикъл.</p><h4>Клинична картина</h4><ul><li><strong>Галакторея:</strong> Продължаващо отделяне на мляко месеци или години след спиране на кърменето.</li><li><strong>Аменорея:</strong> Липса на менструация и атрофия на матката.</li><li><strong>Загуба на либидо:</strong> Поради ниските нива на естрогени.</li></ul><h4>Диференциална диагноза</h4><p>При наличие на <strong>хиперпролактинемия</strong> е задължително изключването на <strong>пролактином</strong> (доброкачествен тумор на хипофизата), особено ако пациентката има неврологични оплаквания като главоболие или зрителни нарушения.</p><ul><li><strong>Изследвания:</strong> Измерване на пролактин, гонадотропини и естрогени в кръвта. При съмнение за тумор се извършва <strong>КГ/МРТ на черепа</strong> (турското седло).</li></ul><h4>Терапия</h4><ul><li><strong>Медикаментозна:</strong> Прилагане на допаминови агонисти (например <strong>бромокриптин</strong>), които потискат секрецията на пролактин.</li><li><strong>Хирургична:</strong> Оперативно отстраняване на пролактинома, ако такъв бъде доказан.</li></ul><h3>В. Сравнителна таблица на нарушенията</h3><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Характеристика</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Синдром на Шихан</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Синдром на Киари-Фромел</span></strong></td></tr><tr><td><strong>Причина</strong></td><td>Исхемия/Некроза след шок</td><td>Дисфункция на пролактиновите клетки</td></tr><tr><td><strong>Лактация</strong></td><td><strong>Липсва / Спира</strong></td><td><strong>Персистира (Галакторея)</strong></td></tr><tr><td><strong>Хормони</strong></td><td>Панхипопитуитаризъм (всички са ниски)</td><td>Висок пролактин, ниски гонадотропини</td></tr><tr><td><strong>Менструация</strong></td><td>Аменорея</td><td>Аменорея</td></tr><tr><td><strong>Лечение</strong></td><td>Хормонално заместване</td><td>Допаминови агонисти</td></tr></tbody></table><hr><h2>Увреждания на симфизата и урологични проблеми в следродовия период</h2><p>По време на бременността естрогените предизвикват физиологично разхлабване на тазовия пръстен. Въпреки тази подготовка, раждането може да доведе до патологични увреждания на <strong>симфизата</strong> или до дисфункции на отделителната система.</p><h3>А. Увреждания на симфизата (Symphysiolysis)</h3><p>Увреждането на симфизата варира от болестно разхлабване до пълна руптура в тежки случаи.</p><h4>Клинична картина</h4><p>Родовата травма е само частичен фактор, тъй като оплакванията често започват още в последните седмици на бременността.</p><ul><li><strong>Болезненост:</strong> Силна болка при натиск върху тазовите кости.</li><li><strong>Мускулни болки:</strong> Рефлекторни болки в аддукторите (вътрешната част на бедрата) и глутеалната мускулатура.</li><li><strong>Двигателни нарушения:</strong> Затруднение при повдигане или сваляне на краката от леглото; невъзможност за стоене на един крак.</li><li><strong>Типична походка:</strong> Характерна \"патешка\" или клатеща се походка.</li></ul><h4>Диагностика и терапия</h4><ul><li><strong>Диагностика:</strong> Поставя се основно чрез рентгеново изследване, което показва раздалечаване на срамните кости.</li><li><strong>Терапия:</strong> Щадене на тялото, аналгетици и използване на специален <strong>симфизен бандаж</strong> (ортопедичен колан). Прогнозата в повечето случаи е добра.</li></ul><h3>Б. Задръжка на урина (Ишурия)</h3><p>Ишурията е често усложнение в първите часове и дни след раждането.</p><ul><li><strong>Етиология:</strong> Дължи се на оток на уретрата или шийката на мехура (често след вагинално-оперативно раждане) или на <strong>пуерперална атония</strong>&nbsp;на пикочния мехур.</li><li><strong>Рискове:</strong> Основната опасност е развитието на асцендираща инфекция към бъбреците.</li><li><strong>Терапия:</strong> Започва се консервативно със спазмолитици и парасимпатикомиметици. При неуспех се извършва еднократна катетеризация при строга асептика.</li></ul><blockquote><strong>ЗАПОМНИ!&nbsp;</strong>Първото спонтанно уриниране след раждането е критичен показател. Празният пикочен мехур позволява на <strong>матката</strong> да се контрахира добре и предпазва от инфекции.</blockquote><h3>В. Инконтиненция на урината</h3><p>Неволното изпускане на урина след раждане е следствие от функционално нарушение на затварящия апарат на мехура поради родова травма.</p><ul><li><strong>Терапия:</strong> Основният метод е <strong>гимнастика на тазовото дъно</strong> за укрепване на мускулатурата. Може да се подкрепи медикаментозно чрез релаксация на <strong>детрузора</strong> (пикочния мускул) или тонизиране на сфинктера.</li></ul><blockquote><strong>ЗАПОМНИ!&nbsp;</strong>Специализираната гимнастика за тазовото дъно трябва да бъде препоръчвана на всяка родилка като част от процеса на обратно развитие.</blockquote><h3>Г. Инфекции на пикочните пътища</h3><p>Следродовият период е рисков за уроинфекции поради персистиращите промени в урогениталния тракт и травмите на уретрата по време на раждането.</p><h4>Етиология и причинители</h4><ul><li><strong>Фактори:</strong> Честа катетеризация по време на раждането, оток на тъканите и задръжка на урина.</li><li><strong>Причинители:</strong> Най-често <strong>E. coli</strong>, Klebsiella, Proteus и Enterobacter.</li></ul><h4>Симптоми и диагностика</h4><ul><li><strong>Симптоми:</strong> <strong>Дизурия</strong> (болезнено уриниране), <strong>алгурия</strong> (парене) и <strong>полакиурия</strong> (чести пориви).</li><li><strong>Диагностика:</strong> Изследване с тест-лента (позитивни за нитрити и левкоцити), седимент и <strong>урокултура</strong> за определяне на конкретния причинител.</li></ul><h4>Терапия</h4><ul><li>Прием на голямо количество течности.</li><li>Целенасочена антибиотична терапия (орална или интравенозна при тежки случаи).</li></ul><blockquote><strong>ЗАПОМНИ!&nbsp;</strong>За превенция на инфекциите, катетеризацията трябва да се извършва само при строги показания, а катетърът да се отстранява възможно най-бързо.</blockquote><hr><h2>Психични промени и заболявания в следродовия период</h2><p>Следродовият период е време на екстремни физиологични и психологични промени. Новата жизнена ситуация, отговорността към новороденото и рязкото спадане на нивата на <strong>прогестерон</strong> и <strong>естрогени</strong> създават специфична психическа уязвимост. Тези състояния варират от леки колебания в настроението до тежки психотични разстройства.</p><h3>А. \"Дни на плач\" (Postpartum Blues)</h3><p>Това е най-честото емоционално състояние, засягащо между <strong>30% и 70%</strong> от родилките. Обикновено се появява през първата седмица след раждането.</p><h4>Етиология и симптоми</h4><ul><li><strong>Причина:</strong> Свързва се с рязкото спадане на нивата на <strong>прогестерон</strong> след изхвърлянето на плацентата, както и със стреса от новата роля.</li><li><strong>Клинична картина:</strong> Плачливост, леко депресивно настроение, умора, раздразнителност и отпадналост.</li><li><strong>Прогноза:</strong> Симптомите са преходни и изчезват от само себе си без специфично медицинско лечение.</li></ul><h4>Терапия и подкрепа</h4><p>Основното внимание трябва да бъде насочено към успокояване на майката за „нормалността“ на състоянието.</p><ul><li><strong>Комплементарни методи:</strong> Ароматерапия (бергамот, ирис, жасмин), светлинна терапия, водолечение и фитотерапия с <strong>жълт кантарион</strong>.</li></ul><h3>Б. Следродова депресия (Postpartum Depression)</h3><p>За разлика от \"дните на плач\", следродовата депресия е по-тежко състояние, което настъпва между <strong>5 и 30 дни</strong> след раждането. Честотата й надвишава <strong>10%</strong>, но много случаи остават недиагностицирани.</p><h4>Симптоми</h4><ul><li>Нарушения в мисленето, концентрацията и съня.</li><li>Силни страхове от несправяне с грижите за детето.</li><li>Намаление на жизнените стимули и екстремна умора.</li><li><strong>Мисли за самоубийство</strong> (критичен маркер).</li></ul><h4>Терапия</h4><p>Изисква задължително психиатрично и психотерапевтично съпътстващо лечение.</p><ul><li><strong>Медикаменти:</strong> Селективни инхибитори на серотониновия транспорт (<strong>SSRI</strong>) и трициклични антидепресанти.</li><li><strong>Социални мерки:</strong> Намаляване на стреса, осигуряване на редовен ритъм на сън и групова терапия.</li></ul><h3>В. Следродова психоза (Postpartum Psychosis)</h3><p>Най-тежкото психично заболяване в пуерпериума, което се среща при около <strong>0.5%</strong> от родилките. Настъпва в късния следродов период (до няколко месеца след раждането).</p><h4>Рискови фактори и симптоми</h4><ul><li><strong>Риск:</strong> По-често при първескини или жени с фамилна анамнеза за психози.</li><li><strong>Симптоми:</strong> Силна възбуда, афективна несдържаност, халюцинации, манийни състояния и разсеяност.</li><li><strong>Опасност:</strong> Висок риск от самоубийство или <strong>опасност за живота на детето</strong>.</li></ul><h4>Терапия</h4><p>Заболяването е спешно състояние и изисква незабавно лечение от психиатър с използването на <strong>невролептици</strong>, транквилизатори и антидепресанти в болнична среда.</p><h3>Г. Психосоматични аспекти и превенция</h3><p>Следродовият период е психосоматичен процес, при който телесните промени и духовното преживяване си взаимодействат непрекъснато.</p><h3>Натоварване на партньорството</h3><p>Новото начало може да бъде изключително натоварващо за двойката.</p><ul><li><strong>Сексуалност:</strong> Намаленото сексуално желание в първите месеци е <strong>физиологично</strong> и не трябва да се тълкува като отхвърляне на партньора.</li><li><strong>Подкрепа:</strong> Активното участие на партньора по време на раждането и след него значително намалява нивата на стрес за майката.</li></ul><h3>Значение на кърменето и връзката (Bonding)</h3><p>Кърменето не е само ендокринен процес, но и интерперсонално събитие. Нарушенията в него често се дължат на страх, липса на защитеност или гневна напрегнатост.</p><h4>Препоръчителни психосоматични мероприятия:</h4><ol><li><strong>Rooming-in:</strong> Престой на майката и бебето в една стая.</li><li><strong>Self-demand feeding:</strong> Хранене на бебето при поискване.</li><li><strong>Bonding:</strong> Стимулиране на ранния кожен контакт.</li><li><strong>Следродова визитация:</strong> Подробно обсъждане на преживяването от раждането с цел превенция на чувства за вина и негативни депресивни реакции.</li></ol><br><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1200px; </p><p>      margin: 2rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.6; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1 { </p><p>      font-weight: 600; </p><p>      font-size: 1.5em;</p><p>      margin-top: 1.5em;</p><p>      margin-bottom: 0.5em;</p><p>      color: #3a5a40;</p><p>      border-bottom: 2px dashed #a3b18a;</p><p>      padding-bottom: 5px;</p><p>    }</p><p>    p { </p><p>      margin: 0.7em 0 1.5em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body { font-size: 16px; }</p><p>      h1 { font-size: 1.3em; }</p><p>    }</p><p>  </style>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>"};
